// build-content-strategy — Validate Upstream Inputs
// Checks all required upstream artifacts are present and well-formed.
//
// CLOUD MODE: all data arrives inline via n8n pipeline. No filesystem access.

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const input = $input.first().json;
const offerArchitecture  = input.offer_architecture;
const strategySynthesis  = input.strategy_synthesis;
const brandPositioning   = input.brand_positioning;
const marketIntelligence = input.market_intelligence;
const storeProfile       = input.store_profile;
const intakePayload      = input.normalized_intake_payload;
const runtimeConfig      = input.runtime_config;
const projectId          = input.project_id;

if (!cloudMode && runtimeConfig && runtimeConfig.cloud_mode) cloudMode = true;

// Required presence checks
if (!offerArchitecture) {
  throw new Error('MISSING_ARTIFACT: offer_architecture is required. Run build-offer-architecture first.');
}
if (!offerArchitecture.core_offer || !offerArchitecture.core_offer.headline) {
  throw new Error('MISSING_ARTIFACT: offer_architecture.core_offer.headline is required.');
}
if (!offerArchitecture.offer_narrative) {
  throw new Error('MISSING_ARTIFACT: offer_architecture.offer_narrative is required.');
}
if (!strategySynthesis) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis is required. Run build-strategy-synthesis first.');
}
if (!strategySynthesis.positioning_focus) {
  throw new Error('MISSING_ARTIFACT: strategy_synthesis.positioning_focus is required.');
}
if (!brandPositioning || !brandPositioning.value_proposition) {
  throw new Error('MISSING_ARTIFACT: brand_positioning with value_proposition is required. Run build-brand-positioning first.');
}
if (!intakePayload) {
  throw new Error('MISSING_ARTIFACT: normalized_intake_payload is required. Run intake-store-input first.');
}
if (!runtimeConfig) {
  throw new Error('MISSING_RUNTIME_CONFIG: runtime_config is required.');
}
if (!projectId) {
  throw new Error('MISSING_INPUT: project_id is required.');
}

console.log('build-content-strategy: inputs validated. cloud=' + cloudMode + ' project=' + projectId);

return [{
  json: {
    project_id:                projectId,
    runtime_config:            runtimeConfig,
    offer_architecture:        offerArchitecture,
    strategy_synthesis:        strategySynthesis,
    brand_positioning:         brandPositioning,
    market_intelligence:       marketIntelligence || null,
    store_profile:             storeProfile || null,
    normalized_intake_payload: intakePayload,
    cloud_mode:                cloudMode,
  },
}];

// build-content-strategy — Build LLM Synthesis Prompt
// Extracts signals from offer_architecture + strategy_synthesis + brand_positioning
// and assembles a structured prompt for content strategy generation.
//
// Evidence boundary: LLM inference from internal signals only.
// All outputs are planning hypotheses requiring human verification.

const input     = $input.first().json;
const oa        = input.offer_architecture;
const ss        = input.strategy_synthesis;
const bp        = input.brand_positioning;
const mi        = input.market_intelligence || {};
const sp        = input.store_profile || {};
const ip        = input.normalized_intake_payload;
const cloudMode = input.cloud_mode || false;

// ─── Extract Offer Architecture signals ──────────────────────────────────────
const coreOffer        = oa.core_offer || {};
const offerHeadline    = coreOffer.headline || '';
const offerVP          = coreOffer.value_proposition || '';
const targetBuyer      = coreOffer.target_buyer || '';
const proofPoints      = (coreOffer.proof_points || []).slice(0, 4);
const pricingTier      = (oa.pricing_logic || {}).tier || 'unknown';
const anchorStrategy   = (oa.pricing_logic || {}).anchor_strategy || '';
const bulkPricing      = (oa.pricing_logic || {}).bulk_pricing || false;
const offerNarrative   = oa.offer_narrative || '';
const bundles          = (oa.bundle_opportunities || []).slice(0, 3).map(function(b) {
  return b.name + (b.rationale ? ': ' + b.rationale.slice(0, 100) : '');
});
const offerGaps        = (oa.offer_gaps || []).slice(0, 3);

// ─── Extract Strategy Synthesis signals ──────────────────────────────────────
const positioningFocus = ss.positioning_focus || {};
const posAngle         = typeof positioningFocus === 'string' ? positioningFocus
  : (positioningFocus.primary_angle || JSON.stringify(positioningFocus));
const opportunities    = (ss.opportunity_priorities || []).slice(0, 3).map(function(o) {
  return typeof o === 'string' ? o : (o.opportunity || JSON.stringify(o));
});
const messagingPriorities = (ss.messaging_priorities || []).slice(0, 4);
const validationQs     = (ss.validation_questions || []).slice(0, 3).map(function(q) {
  return typeof q === 'string' ? q : (q.question || JSON.stringify(q));
});

// ─── Extract Brand Positioning signals ───────────────────────────────────────
const brandRole        = bp.brand_role || 'specialist';
const valueProposition = bp.value_proposition || '';
const differentiators  = (bp.differentiators || []).slice(0, 4);
const brandTraits      = (bp.brand_traits || []).slice(0, 4);
const toneStyle        = (bp.tone_of_voice && bp.tone_of_voice.style) ? bp.tone_of_voice.style : 'technical-trustworthy';
const messagingPillars = (bp.messaging_pillars || []).slice(0, 3).map(function(p) {
  return typeof p === 'string' ? p : (p.pillar_name + (p.description ? ': ' + p.description.slice(0, 80) : ''));
});
const emotionalBenefits   = (bp.emotional_benefits || []).slice(0, 3);
const functionalBenefits  = (bp.functional_benefits || []).slice(0, 3);

// ─── Extract intake signals ───────────────────────────────────────────────────
const vertical          = ip.vertical || 'unknown';
const pricePositioning  = ip.price_positioning || 'unknown';
const primaryMarket     = ip.primary_market || 'DE';
const primaryLanguage   = ip.primary_language || 'de';
const projectName       = ip.project_name || ip.project_id || 'the store';
const seoGoal           = ip.seo_goal || 'visibility';
const aeoGoal           = ip.aeo_goal || null;
const faqIntensity      = ip.faq_intensity || 'medium';
const knowledgePriority = ip.knowledge_content_priority || null;

// ─── Extract Market Intelligence signals (optional) ──────────────────────────
const audienceSegments  = (mi.audience_segments || []).slice(0, 3).map(function(s) {
  return typeof s === 'string' ? s : ((s.segment_name || 'segment') + (s.description ? ': ' + String(s.description).slice(0, 80) : ''));
});
const coreProblems      = (mi.core_problems || []).slice(0, 4).map(function(p) {
  return typeof p === 'string' ? p : (p.problem || JSON.stringify(p));
});
const trendSignals      = (mi.trend_signals || []).slice(0, 3);
const trustFactors      = (mi.trust_factors || []).slice(0, 3).map(function(t) {
  return typeof t === 'string' ? t : (t.factor || JSON.stringify(t));
});

// ─── Build prompt ─────────────────────────────────────────────────────────────
const faqNote = faqIntensity === 'high'
  ? 'FAQ content is HIGH priority — include substantial FAQ coverage in content pillars and page strategy.'
  : faqIntensity === 'none' ? 'FAQ content is NOT required for this project.'
  : 'Include moderate FAQ coverage as relevant.';

const prompt = [
  'You are a senior content strategist building the content strategy for a new Shopify store.',
  'Based on the offer architecture and strategic intelligence below, generate a structured content strategy.',
  '',
  '## Store Context',
  'Project: ' + projectName,
  'Vertical: ' + vertical,
  'Price positioning: ' + pricePositioning,
  'Primary market: ' + primaryMarket,
  'Primary language: ' + primaryLanguage,
  'SEO goal: ' + seoGoal,
  aeoGoal ? 'AEO goal: ' + aeoGoal : '',
  knowledgePriority ? 'Knowledge content priority: ' + knowledgePriority : '',
  faqNote,
  '',
  '## Offer Architecture (Phase 6a Output)',
  '### Core Offer',
  'Headline: ' + offerHeadline,
  'Value proposition: ' + offerVP,
  'Target buyer: ' + targetBuyer,
  proofPoints.length ? 'Proof points: ' + proofPoints.join(' | ') : '',
  'Pricing tier: ' + pricingTier + (bulkPricing ? ' (bulk pricing available)' : ''),
  anchorStrategy ? 'Anchor strategy: ' + anchorStrategy : '',
  bundles.length ? 'Bundles: ' + bundles.join(' / ') : '',
  '',
  '### Offer Narrative',
  offerNarrative,
  '',
  '## Strategic Intelligence',
  '### Positioning Focus',
  posAngle,
  '',
  '### Brand Value Proposition',
  valueProposition,
  '',
  '### Brand Role & Tone',
  'Brand role: ' + brandRole,
  'Tone of voice: ' + toneStyle,
  brandTraits.length ? 'Brand traits: ' + (brandTraits.map(function(t) { return typeof t === 'string' ? t : JSON.stringify(t); }).join(', ')) : '',
  messagingPillars.length ? '### Messaging Pillars\n' + messagingPillars.map(function(p) { return '- ' + p; }).join('\n') : '',
  '',
  opportunities.length ? '### Strategic Opportunities\n' + opportunities.map(function(o, i) { return (i+1) + '. ' + o; }).join('\n') : '',
  coreProblems.length ? '### Customer Problems to Address\n' + coreProblems.map(function(p) { return '- ' + p; }).join('\n') : '',
  audienceSegments.length ? '### Audience Segments\n' + audienceSegments.map(function(s) { return '- ' + s; }).join('\n') : '',
  trustFactors.length ? '### Trust Factors\n' + trustFactors.map(function(t) { return '- ' + t; }).join('\n') : '',
  emotionalBenefits.length ? '### Emotional Benefits\n' + emotionalBenefits.map(function(b) { return '- ' + (typeof b === 'string' ? b : JSON.stringify(b)); }).join('\n') : '',
  differentiators.length ? '### Differentiators\n' + differentiators.map(function(d) { return '- ' + (typeof d === 'string' ? d : JSON.stringify(d)); }).join('\n') : '',
  trendSignals.length ? '### Trend Signals\n' + trendSignals.map(function(t) { return '- ' + (typeof t === 'string' ? t : JSON.stringify(t)); }).join('\n') : '',
  validationQs.length ? '### Open Validation Questions\n' + validationQs.map(function(q) { return '- ' + q; }).join('\n') : '',
  offerGaps.length ? '### Offer Gaps to Address in Content\n' + offerGaps.map(function(g) { return '- ' + g; }).join('\n') : '',
  '',
  '## Output Requirements',
  'Return a JSON object with exactly this structure (no markdown fences, pure JSON):',
  '{',
  '  "messaging_hierarchy": {',
  '    "primary_message": "The single most important message the store must communicate",',
  '    "supporting_messages": ["Message 2", "Message 3", "Message 4"],',
  '    "proof_statements": ["Concrete claim 1", "Concrete claim 2"]',
  '  },',
  '  "content_pillars": [',
  '    {',
  '      "pillar": "Pillar topic name",',
  '      "rationale": "Why strategically important",',
  '      "content_types": ["guide", "comparison", "FAQ"],',
  '      "target_keywords": ["keyword 1", "keyword 2"]',
  '    }',
  '  ],',
  '  "page_strategy": {',
  '    "homepage_angle": "Primary message and CTA direction for the homepage",',
  '    "collection_page_strategy": "How collection pages should be written and structured",',
  '    "product_page_strategy": "Product page tone, proof point usage, and CTA approach",',
  '    "blog_strategy": "Editorial direction for blog/knowledge content",',
  '    "landing_page_priorities": ["Priority landing page 1", "Priority landing page 2"]',
  '  },',
  '  "seo_content_plan": {',
  '    "primary_keyword_clusters": ["cluster 1", "cluster 2"],',
  '    "long_tail_priorities": ["long-tail phrase 1", "long-tail phrase 2"],',
  '    "featured_snippet_targets": ["question to target 1"],',
  '    "faq_topic_clusters": ["FAQ cluster 1", "FAQ cluster 2"]',
  '  },',
  '  "editorial_voice": {',
  '    "tone": "Tone descriptor consistent with brand",',
  '    "style_rules": ["Rule 1 (e.g. use second person)", "Rule 2", "Rule 3"],',
  '    "vocabulary": {',
  '      "use": ["word/phrase to use"],',
  '      "avoid": ["word/phrase to avoid"]',
  '    }',
  '  },',
  '  "content_gaps": ["Gap or missing content area"],',
  '  "validation_questions": ["Question needing merchant input before content creation"]',
  '}',
  '',
  'Rules:',
  '- content_pillars: minimum 2, maximum 6',
  '- messaging_hierarchy.supporting_messages: exactly 3–5 items',
  '- messaging_hierarchy.proof_statements: at least 2 items',
  '- editorial_voice.style_rules: at least 3 concrete rules',
  '- All content grounded in the offer architecture and strategic intelligence above',
  '- Primary message and editorial voice MUST be consistent with tone: ' + toneStyle,
  '- Return pure JSON only — no markdown fences, no commentary outside the JSON',
].filter(function(l) { return l !== null && l !== undefined; }).join('\n');

return [{
  json: {
    llm_prompt:                prompt,
    project_id:                input.project_id,
    runtime_config:            input.runtime_config,
    offer_architecture:        oa,
    strategy_synthesis:        ss,
    brand_positioning:         bp,
    market_intelligence:       mi,
    store_profile:             sp,
    normalized_intake_payload: ip,
    cloud_mode:                cloudMode,
    tone_style:                toneStyle,
  },
}];

// build-content-strategy — Parse, Validate, and Write
//
// Steps:
//   1. Parse LLM JSON object response
//   2. Inline schema validation (required fields, structure checks)
//   3. Return content_strategy inline with runtime envelope
//
// CLOUD MODE: fully compatible. No AJV, no filesystem write.

function buildRunId() {
  const ts = new Date().toISOString().replace(/[-:T.Z]/g, '').slice(0, 14);
  const rand = Math.random().toString(36).slice(2, 6);
  return 'run-' + ts + '-' + rand;
}

let cloudMode = false;
try { require('fs'); } catch (_e) { cloudMode = true; }

const llmOutput = $input.first().json;
const upstream  = $node['Build LLM Synthesis Prompt'].json;

if (!cloudMode && upstream.cloud_mode) cloudMode = true;
if (!cloudMode && upstream.runtime_config && upstream.runtime_config.cloud_mode) cloudMode = true;

const projectId        = upstream.project_id;
const runtimeConfig    = upstream.runtime_config;
const offerArchitecture = upstream.offer_architecture;
const toneStyle         = upstream.tone_style || 'technical-trustworthy';

// ─── Step 1: Parse LLM response ──────────────────────────────────────────────
const rawText = (llmOutput.message && llmOutput.message.content)
  ? llmOutput.message.content
  : (typeof llmOutput === 'string' ? llmOutput : JSON.stringify(llmOutput));

let contentStrategy;
try {
  let cleaned = rawText.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  }
  const parsed = JSON.parse(cleaned);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
    contentStrategy = parsed;
  } else {
    throw new Error('Expected a JSON object at root, got: ' + typeof parsed);
  }
} catch (err) {
  throw new Error(
    'LLM_PARSE_ERROR: Failed to parse LLM response as JSON object: ' + err.message +
    '. Raw response (first 500 chars): ' + String(rawText).slice(0, 500)
  );
}

// ─── Step 2: Inline schema validation ────────────────────────────────────────
const cloudWarnings = [];

// Required top-level fields
const REQUIRED = ['messaging_hierarchy', 'content_pillars', 'page_strategy', 'seo_content_plan', 'editorial_voice'];
for (const f of REQUIRED) {
  if (!contentStrategy[f]) {
    throw new Error('SCHEMA_VIOLATION: content_strategy.' + f + ' is required.');
  }
}

// messaging_hierarchy
const mh = contentStrategy.messaging_hierarchy;
if (!mh.primary_message) {
  throw new Error('SCHEMA_VIOLATION: messaging_hierarchy.primary_message is required.');
}
if (!Array.isArray(mh.supporting_messages) || mh.supporting_messages.length < 2) {
  throw new Error('SCHEMA_VIOLATION: messaging_hierarchy.supporting_messages must have at least 2 items.');
}
if (!Array.isArray(mh.proof_statements) || mh.proof_statements.length < 2) {
  throw new Error('SCHEMA_VIOLATION: messaging_hierarchy.proof_statements must have at least 2 items.');
}

// content_pillars
if (!Array.isArray(contentStrategy.content_pillars) || contentStrategy.content_pillars.length < 2) {
  throw new Error('SCHEMA_VIOLATION: content_pillars must be an array with at least 2 items.');
}
for (let i = 0; i < contentStrategy.content_pillars.length; i++) {
  const p = contentStrategy.content_pillars[i];
  if (!p.pillar || !p.rationale) {
    throw new Error('SCHEMA_VIOLATION: content_pillars[' + i + '] must have pillar and rationale.');
  }
  if (!Array.isArray(p.content_types) || p.content_types.length === 0) {
    throw new Error('SCHEMA_VIOLATION: content_pillars[' + i + '].content_types must be a non-empty array.');
  }
}

// page_strategy
const ps = contentStrategy.page_strategy;
if (!ps.homepage_angle) {
  throw new Error('SCHEMA_VIOLATION: page_strategy.homepage_angle is required.');
}

// editorial_voice
const ev = contentStrategy.editorial_voice;
if (!ev.tone) {
  throw new Error('SCHEMA_VIOLATION: editorial_voice.tone is required.');
}
if (!Array.isArray(ev.style_rules) || ev.style_rules.length < 2) {
  throw new Error('SCHEMA_VIOLATION: editorial_voice.style_rules must have at least 2 items.');
}

// ─── Step 3: Build runtime envelope ──────────────────────────────────────────
const runId       = buildRunId();
const executionTs = new Date().toISOString();

const outputSummary = {
  pillar_count:           contentStrategy.content_pillars.length,
  supporting_message_count: mh.supporting_messages.length,
  proof_statement_count:  mh.proof_statements.length,
  style_rule_count:       ev.style_rules.length,
  primary_keyword_cluster_count: (contentStrategy.seo_content_plan.primary_keyword_clusters || []).length,
  faq_cluster_count:      (contentStrategy.seo_content_plan.faq_topic_clusters || []).length,
  content_gap_count:      (contentStrategy.content_gaps || []).length,
  editorial_tone:         ev.tone,
};

const envelope = {
  run_id:     runId,
  phase:      'content-strategy',
  project_id: projectId,
  timestamp:  executionTs,
  cloud_mode: cloudMode,
  validation: {
    result:    'PASS',
    errors:    [],
    warnings:  cloudWarnings,
  },
  diagnostics: {
    output_summary: outputSummary,
  },
  lineage: {
    depends_on: ['build-offer-architecture', 'build-strategy-synthesis', 'build-brand-positioning'],
    produced_by: 'build-content-strategy',
  },
};

return [{
  json: {
    project_id:       projectId,
    artifact_name:    'content-strategy',
    artifact_path:    null,
    content_strategy: contentStrategy,
    runtime_config:   runtimeConfig,
    status:           'SUCCESS',
    cloud_mode:       cloudMode,
    cloud_warnings:   cloudWarnings,
    notes:            [],
    envelope:         envelope,
  },
}];
